    const size_t min_required_size = header_len + 1;

    // Stage 1: Header Parsing
    if (data_size < min_required_size) {
        return -1;
    }

    // Verify magic number
    if (compressed_data[0]!= CMP_MAGIC_0 || compressed_data[1]!= CMP_MAGIC_1) {
        return -1;
    }

    // Read compression type
    ctx->compression_type = compressed_data[2];

    // Read expected decompressed size (32-bit little-endian)
    uint32_t expected_size_32 = (uint32_t)compressed_data[3] |
                                 ((uint32_t)compressed_data[4] << 8) |
                                 ((uint32_t)compressed_data[5] << 16) |
                                 ((uint32_t)compressed_data[6] << 24);
    size_t expected_size = (size_t)expected_size_32;

    // Check for reasonable expected size to avoid huge allocations
    if (expected_size > (1 << 30)) { // 1GB max, adjust as needed
        return -1;
    }

    // Allocate temporary buffer for decompression
    ctx->temp_buffer = (unsigned char *)malloc(expected_size);
    if (ctx->temp_buffer == NULL) {
        return -1;
    }
    ctx->buffer_size = expected_size;

    // Stage 2: Data Decompression
    const size_t payload_len = data_size - header_len - 1;
    const unsigned char *payload = &compressed_data[header_len];

    if (ctx->compression_type == 0) {
        // Raw type: direct copy
        if (payload_len!= expected_size) {
            goto error;
        }
        memcpy(ctx->temp_buffer, payload, payload_len);
    } else if (ctx->compression_type == 1) {
        // RLE type: (count, value) pairs
        if (payload_len % 2!= 0) {
            goto error;
        }

        size_t out_idx = 0;
        for (size_t i = 0; i < payload_len; i += 2) {
            uint8_t count = payload[i];
            uint8_t val = payload[i + 1];

            if (out_idx + count > ctx->buffer_size) {
                goto error;
            }

            memset(ctx->temp_buffer + out_idx, val, count);
            out_idx += count;
        }

        if (out_idx!= expected_size) {
            goto error;
        }
    } else {
        // Unknown compression type
        goto error;
    }

    // Stage 3: Integrity Verification
    uint8_t calc_checksum = 0;
    for (size_t i = 0; i < ctx->buffer_size; i++) {
        calc_checksum += ctx->temp_buffer[i];
    }
    uint8_t file_checksum = compressed_data[data_size - 1];
    if (calc_checksum!= file_checksum) {
        goto error;
    }

    // Success: return 0, caller is responsible for freeing temp_buffer
    return 0;

error:
    // Free temp buffer once on error
    free(ctx->temp_buffer);
    ctx->temp_buffer = NULL;
    return -1;
}

